import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';

export type UserVm = {
  id: string;
  name: string;
  email: string;
  role: 'student' | 'teacher' | 'parent' | 'admin';
  status: 'active' | 'inactive';
  createdAt: string;
};

export type StatsVm = {
  totalStudents: number;
  totalTeachers: number;
  totalCourses: number;
  totalRevenue: number;
};

@Component({
  selector: 'app-admin-dashboard',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './admin-dashboard.component.html',
  styleUrls: ['./admin-dashboard.component.scss']
})
export class AdminDashboardComponent {
  isLoading = signal(true);
  activeTab = signal<'overview' | 'users' | 'courses'>('overview');

  stats = signal<StatsVm>({
    totalStudents: 12500,
    totalTeachers: 45,
    totalCourses: 248,
    totalRevenue: 125000
  });

  recentUsers = signal<UserVm[]>([
    { id: 'u1', name: 'Youssef Amrani', email: 'youssef@email.com', role: 'student', status: 'active', createdAt: '2026-03-20' },
    { id: 'u2', name: 'M. Amine', email: 'amine@email.com', role: 'teacher', status: 'active', createdAt: '2026-03-19' },
    { id: 'u3', name: 'Mme Fatima', email: 'fatima@email.com', role: 'parent', status: 'active', createdAt: '2026-03-18' },
    { id: 'u4', name: 'Sofia Amrani', email: 'sofia@email.com', role: 'student', status: 'inactive', createdAt: '2026-03-15' }
  ]);

  recentCourses = signal([
    { id: 'c1', title: 'Algèbre — Bases et exercices', teacher: 'M. Amine', students: 45, status: 'published' },
    { id: 'c2', title: 'Physique — Mécanique', teacher: 'Mme Salma', students: 32, status: 'published' },
    { id: 'c3', title: 'Trigonométrie', teacher: 'M. Amine', students: 0, status: 'draft' }
  ]);

  constructor() {
    setTimeout(() => this.isLoading.set(false), 600);
  }

  setTab(tab: 'overview' | 'users' | 'courses') {
    this.activeTab.set(tab);
  }

  getRoleLabel(role: string): string {
    switch (role) {
      case 'student': return 'Étudiant';
      case 'teacher': return 'Professeur';
      case 'parent': return 'Parent';
      case 'admin': return 'Admin';
      default: return role;
    }
  }

  getRoleColor(role: string): string {
    switch (role) {
      case 'student': return 'bg-blue-100 text-blue-700';
      case 'teacher': return 'bg-green-100 text-green-700';
      case 'parent': return 'bg-purple-100 text-purple-700';
      case 'admin': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  }
}
<div class="min-h-screen bg-[#F8F9FA] py-8">
  <div class="mx-auto w-full max-w-7xl px-4">
    <!-- Loading -->
    <div *ngIf="isLoading()" class="flex items-center justify-center py-20">
      <div class="h-12 w-12 animate-spin rounded-full border-4 border-gray-200 border-t-[#1A73E8]"></div>
    </div>

    <!-- Content -->
    <div *ngIf="!isLoading()">
      <!-- Header -->
      <div class="mb-8 overflow-hidden rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
        <div class="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h1 class="text-2xl font-bold text-gray-900 sm:text-3xl">Tableau de bord Admin</h1>
            <p class="mt-1 text-gray-600">Gérez la plateforme EduPlatform</p>
          </div>
          <button class="rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] px-4 py-2 text-sm font-semibold text-white">
            + Nouvel utilisateur
          </button>
        </div>
      </div>

      <!-- Tabs -->
      <div class="mb-6 border-b border-gray-200">
        <nav class="-mb-px flex gap-6">
          <button
            (click)="setTab('overview')"
            [class]="activeTab() === 'overview' ? 'border-[#1A73E8] text-[#1A73E8]' : 'border-transparent text-gray-500 hover:border-gray-300 hover:text-gray-700'"
            class="whitespace-nowrap border-b-2 py-4 text-sm font-medium transition">
            Aperçu
          </button>
          <button
            (click)="setTab('users')"
            [class]="activeTab() === 'users' ? 'border-[#1A73E8] text-[#1A73E8]' : 'border-transparent text-gray-500 hover:border-gray-300 hover:text-gray-700'"
            class="whitespace-nowrap border-b-2 py-4 text-sm font-medium transition">
            Utilisateurs
          </button>
          <button
            (click)="setTab('courses')"
            [class]="activeTab() === 'courses' ? 'border-[#1A73E8] text-[#1A73E8]' : 'border-transparent text-gray-500 hover:border-gray-300 hover:text-gray-700'"
            class="whitespace-nowrap border-b-2 py-4 text-sm font-medium transition">
            Cours
          </button>
        </nav>
      </div>

      <!-- Overview Tab -->
      <div *ngIf="activeTab() === 'overview'">
        <!-- Stats Cards -->
        <div class="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
          <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
            <p class="text-sm text-gray-500">Étudiants</p>
            <p class="mt-1 text-3xl font-bold text-gray-900">{{ stats().totalStudents | number }}</p>
          </div>
          <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
            <p class="text-sm text-gray-500">Professeurs</p>
            <p class="mt-1 text-3xl font-bold text-gray-900">{{ stats().totalTeachers }}</p>
          </div>
          <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
            <p class="text-sm text-gray-500">Cours</p>
            <p class="mt-1 text-3xl font-bold text-gray-900">{{ stats().totalCourses }}</p>
          </div>
          <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
            <p class="text-sm text-gray-500">Revenus</p>
            <p class="mt-1 text-3xl font-bold text-[#34A853]">{{ stats().totalRevenue | number }} DH</p>
          </div>
        </div>
      </div>

      <!-- Users Tab -->
      <div *ngIf="activeTab() === 'users'" class="rounded-2xl border border-gray-200 bg-white shadow-sm">
        <div class="overflow-x-auto">
          <table class="w-full">
            <thead>
              <tr class="border-b border-gray-200 bg-gray-50">
                <th class="px-6 py-4 text-left text-sm font-medium text-gray-500">Nom</th>
                <th class="px-6 py-4 text-left text-sm font-medium text-gray-500">Email</th>
                <th class="px-6 py-4 text-left text-sm font-medium text-gray-500">Rôle</th>
                <th class="px-6 py-4 text-left text-sm font-medium text-gray-500">Statut</th>
                <th class="px-6 py-4 text-left text-sm font-medium text-gray-500">Créé le</th>
                <th class="px-6 py-4 text-right text-sm font-medium text-gray-500">Actions</th>
              </tr>
            </thead>
            <tbody>
              <tr *ngFor="let user of recentUsers()" class="border-b border-gray-100">
                <td class="px-6 py-4 font-medium text-gray-900">{{ user.name }}</td>
                <td class="px-6 py-4 text-gray-600">{{ user.email }}</td>
                <td class="px-6 py-4">
                  <span [class]="'rounded-full px-3 py-1 text-xs font-medium ' + getRoleColor(user.role)">
                    {{ getRoleLabel(user.role) }}
                  </span>
                </td>
                <td class="px-6 py-4">
                  <span [class]="user.status === 'active' ? 'text-green-600' : 'text-gray-400'" class="text-sm">
                    {{ user.status === 'active' ? 'Actif' : 'Inactif' }}
                  </span>
                </td>
                <td class="px-6 py-4 text-gray-600">{{ user.createdAt | date:'dd/MM/yyyy' }}</td>
                <td class="px-6 py-4 text-right">
                  <button class="text-[#1A73E8] hover:underline">Modifier</button>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>

      <!-- Courses Tab -->
      <div *ngIf="activeTab() === 'courses'" class="rounded-2xl border border-gray-200 bg-white shadow-sm">
        <div class="overflow-x-auto">
          <table class="w-full">
            <thead>
              <tr class="border-b border-gray-200 bg-gray-50">
                <th class="px-6 py-4 text-left text-sm font-medium text-gray-500">Cours</th>
                <th class="px-6 py-4 text-left text-sm font-medium text-gray-500">Professeur</th>
                <th class="px-6 py-4 text-left text-sm font-medium text-gray-500">Étudiants</th>
                <th class="px-6 py-4 text-left text-sm font-medium text-gray-500">Statut</th>
                <th class="px-6 py-4 text-right text-sm font-medium text-gray-500">Actions</th>
              </tr>
            </thead>
            <tbody>
              <tr *ngFor="let course of recentCourses()" class="border-b border-gray-100">
                <td class="px-6 py-4 font-medium text-gray-900">{{ course.title }}</td>
                <td class="px-6 py-4 text-gray-600">{{ course.teacher }}</td>
                <td class="px-6 py-4 text-gray-600">{{ course.students }}</td>
                <td class="px-6 py-4">
                  <span [class]="course.status === 'published' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'" class="rounded-full px-3 py-1 text-xs font-medium">
                    {{ course.status === 'published' ? 'Publié' : 'Brouillon' }}
                  </span>
                </td>
                <td class="px-6 py-4 text-right">
                  <button class="text-[#1A73E8] hover:underline">Voir</button>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  </div>
</div>
